import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import useFullscreen from '../../hooks/useFullscreen'
import './styles.css'

const POLL_INTERVAL_MS = 5000

function formatTime(milliseconds) {
  if (!Number.isFinite(milliseconds)) return '--:--'
  const totalSeconds = Math.max(0, Math.floor(milliseconds / 1000))
  const minutes = Math.floor(totalSeconds / 60)
  const seconds = totalSeconds % 60
  return `${minutes}:${seconds.toString().padStart(2, '0')}`
}

async function fetchJson(url, options) {
  const response = await fetch(url, options)
  if (!response.ok) {
    const body = await response.json().catch(() => ({}))
    const message = body.error || `Request failed with status ${response.status}`
    throw new Error(message)
  }
  return response.json()
}

function useSpotifyStatus() {
  const [state, setState] = useState({
    loading: true,
    error: '',
    status: {
      configured: false,
      authenticated: false,
      username: '',
      tokenExpiresAt: 0,
      playback: null,
      playbackError: null,
    },
    lastUpdated: null,
  })

  const load = useCallback(async () => {
    try {
      const data = await fetchJson('/spotify/status')
      setState({
        loading: false,
        error: '',
        status: {
          configured: Boolean(data.configured),
          authenticated: Boolean(data.authenticated),
          username: data.username || '',
          tokenExpiresAt: Number(data.tokenExpiresAt) || 0,
          playback: data.playback || null,
          playbackError: data.playbackError || null,
        },
        lastUpdated: Date.now(),
      })
    } catch (error) {
      setState((prev) => ({
        ...prev,
        loading: false,
        error: error.message || 'Unable to load Spotify status.',
      }))
    }
  }, [])

  useEffect(() => {
    let cancelled = false
    let intervalId = null

    async function start() {
      await load()
      if (cancelled) return
      intervalId = setInterval(load, POLL_INTERVAL_MS)
    }

    start()
    return () => {
      cancelled = true
      if (intervalId) {
        clearInterval(intervalId)
      }
    }
  }, [load])

  return { ...state, reload: load }
}

export default function SpotifyRecordDashboard() {
  const { error, status, reload } = useSpotifyStatus()
  const containerRef = useRef(null)
  const [recordSize, setRecordSize] = useState(0)
  const [containerHeight, setContainerHeight] = useState(0)
  const [pendingAction, setPendingAction] = useState(null)
  const playback = status.playback
  const isPlaying = playback?.isPlaying
  const [displayProgress, setDisplayProgress] = useState(0)
  const [displayDuration, setDisplayDuration] = useState(0)
  const playbackStateRef = useRef(null)
  const { isFullscreen, toggleFullscreen, showButton, supported, buttonInteractionProps } =
    useFullscreen(containerRef)

  useEffect(() => {
    const container = containerRef.current
    if (!container) return undefined

    const updateSize = () => {
      const rect = container.getBoundingClientRect()
      const next = Math.floor(Math.max(0, rect.width))
      setRecordSize(next > 0 ? next : 0)
      setContainerHeight(Math.floor(Math.max(0, rect.height)))
    }

    updateSize()

    if (typeof ResizeObserver !== 'undefined') {
      const observer = new ResizeObserver(updateSize)
      observer.observe(container)
      return () => observer.disconnect()
    }

    window.addEventListener('resize', updateSize)
    return () => window.removeEventListener('resize', updateSize)
  }, [isFullscreen])

  useEffect(() => {
    if (!playback) {
      playbackStateRef.current = null
      setDisplayDuration(0)
      setDisplayProgress(0)
      return
    }

    const duration = Number(playback.durationMs) || 0
    const progress = Number(playback.progressMs) || 0
    const now = Date.now()
    playbackStateRef.current = {
      duration,
      lastProgress: Math.min(duration || Number.MAX_SAFE_INTEGER, progress),
      lastSync: now,
      isPlaying: Boolean(playback.isPlaying),
    }
    setDisplayDuration(duration)
    setDisplayProgress(Math.min(duration || Number.MAX_SAFE_INTEGER, progress))
  }, [playback?.updatedAt, playback?.durationMs, playback?.progressMs, playback?.isPlaying])

  useEffect(() => {
    const interval = setInterval(() => {
      const state = playbackStateRef.current
      if (!state || !state.duration) return
      if (!state.isPlaying) {
        setDisplayProgress(state.lastProgress)
        return
      }
      const now = Date.now()
      const elapsed = now - state.lastSync
      if (elapsed <= 0) return
      const projected = Math.min(state.duration, state.lastProgress + elapsed)
      state.lastProgress = projected
      state.lastSync = now
      setDisplayProgress(projected)
    }, 200)

    return () => clearInterval(interval)
  }, [])

  const progressPercent = useMemo(() => {
    if (!displayDuration || displayDuration <= 0) return 0
    return Math.max(0, Math.min(100, (displayProgress / displayDuration) * 100))
  }, [displayProgress, displayDuration])

  const progressLabel = useMemo(() => {
    if (!displayDuration || displayDuration <= 0) {
      return '--:-- / --:--'
    }
    return `${formatTime(displayProgress)} / ${formatTime(displayDuration)}`
  }, [displayProgress, displayDuration])

  const controlsDisabled = !status.authenticated || Boolean(pendingAction)

  // Compact layout when height < 480px or width < 340px (and not fullscreen)
  const isCompact = !isFullscreen && (containerHeight > 0 && containerHeight < 480 || recordSize > 0 && recordSize < 340)

  const dynamicStyles = useMemo(() => {
    if (!recordSize) {
      return undefined
    }

    const panelWidth = Math.round(
      Math.max(260, Math.min(recordSize * 0.62, recordSize * 0.82)),
    )

    return {
      '--spotify-record-size': `${recordSize}px`,
      '--spotify-record-window': `${Math.round(recordSize / 2)}px`,
      '--spotify-panel-width': `${panelWidth}px`,
    }
  }, [recordSize])

  const handleControl = useCallback(
    async (action) => {
      if (controlsDisabled) return
      setPendingAction(action)
      try {
        await fetchJson('/spotify/control', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({ action }),
        })
        await reload()
      } catch (err) {
        console.error('Spotify control failed', err)
      } finally {
        setPendingAction(null)
      }
    },
    [controlsDisabled, reload],
  )

  const durationLabel = progressLabel.split('/')

  return (
    <div
      className={`dashboard spotify-dashboard${
        isFullscreen ? ' spotify-dashboard--fullscreen dashboard--fullscreen' : ''
      }${isCompact ? ' spotify-dashboard--compact' : ''}`}
      ref={containerRef}
      style={dynamicStyles}
    >
      {isCompact ? (
        <div className="spotify-dashboard__compact-art">
          {playback?.albumCover ? (
            <img src={playback.albumCover} alt="Album artwork" className="spotify-dashboard__compact-art-img" />
          ) : (
            <div className="spotify-dashboard__record-placeholder">🎵</div>
          )}
        </div>
      ) : (
        <div className="spotify-dashboard__record-wrapper">
          <div
            className={`spotify-dashboard__record ${
              isPlaying ? 'spotify-dashboard__record--spinning' : ''
            }`}
          >
            <div className="spotify-dashboard__record-disc" />
            <div
              className={`spotify-dashboard__record-overlay ${
                isPlaying ? 'spotify-dashboard__record-overlay--spinning' : ''
              }`}
            >
              {playback?.albumCover ? (
                <img src={playback.albumCover} alt="Album artwork" />
              ) : (
                <div className="spotify-dashboard__record-placeholder">🎵</div>
              )}
              <div className="spotify-dashboard__record-ring" />
              <div className="spotify-dashboard__record-dot" />
            </div>
          </div>
        </div>
      )}

      {supported ? (
        <button
          type="button"
          className={`dashboard__fullscreen-button spotify-dashboard__fullscreen${
            showButton ? ' is-visible' : ''
          }`}
          onClick={toggleFullscreen}
          aria-label={isFullscreen ? 'Exit fullscreen' : 'Enter fullscreen'}
          {...buttonInteractionProps}
        >
          {isFullscreen ? '🗗' : '⛶'}
        </button>
      ) : null}

      <div className="spotify-dashboard__panel">
        <div className="spotify-dashboard__meta">
          <div className="spotify-dashboard__title">
            {status.configured ? playback?.title || 'Nothing playing' : 'Connect Spotify'}
          </div>
          {status.configured && status.authenticated ? (
            <div className="spotify-dashboard__artist">{playback?.artist || ''}</div>
          ) : (
            <div className="spotify-dashboard__artist">
              {status.configured
                ? 'Authorize Spotify in the settings panel to resume playback.'
                : 'Add your Spotify credentials in the settings panel.'}
            </div>
          )}
        </div>

        <div className="spotify-dashboard__progress" aria-hidden={!playback}>
          <div className="spotify-dashboard__progress-bar" style={{ width: `${progressPercent}%` }} />
        </div>
        <div className="spotify-dashboard__progress-label" aria-hidden={!playback}>
          <span className="spotify-dashboard__progress-current">{formatTime(displayProgress)}</span>
          <span>{durationLabel[1] ? durationLabel[1].trim() : '--:--'}</span>
        </div>

        <div className="spotify-dashboard__controls">
          <button
            type="button"
            className="spotify-dashboard__button"
            onClick={() => handleControl('previous')}
            disabled={controlsDisabled}
          >
            ⏮
          </button>
          <button
            type="button"
            className="spotify-dashboard__button spotify-dashboard__button--play"
            onClick={() => handleControl(isPlaying ? 'pause' : 'play')}
            disabled={controlsDisabled}
          >
            {isPlaying ? '❚❚' : '▶'}
          </button>
          <button
            type="button"
            className="spotify-dashboard__button"
            onClick={() => handleControl('next')}
            disabled={controlsDisabled}
          >
            ⏭
          </button>
        </div>
      </div>

      {error ? (
        <footer className="spotify-dashboard__footer">
          <span className="spotify-dashboard__error">{error}</span>
        </footer>
      ) : null}
    </div>
  )
}
