import React, { useState, useEffect, useRef } from 'react';
import { getAppSettings } from '../data/apps';
import useResponsiveFontScale from '../hooks/useResponsiveFontScale';

const WeatherApp = ({ appId = 'weather' }) => {
  const [weatherData, setWeatherData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [settings, setSettings] = useState(getAppSettings(appId));
  const containerRef = useRef(null);
  const scale = useResponsiveFontScale(containerRef, {
    baseWidth: 280,
    baseHeight: 260,
    min: 0.7,
    max: 2.4
  });

  useEffect(() => {
    setSettings(getAppSettings(appId));
  }, [appId]);

  useEffect(() => {
    if (settings.location) {
      fetchWeather();
    }
  }, [settings.location, settings.units]); // eslint-disable-line react-hooks/exhaustive-deps

  const fetchWeather = async () => {
    if (!settings.location) return;

    setLoading(true);
    setError('');

    try {
      // First, geocode the location
      const geoRes = await fetch(
        `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(settings.location)}&count=1&language=en&format=json`
      );

      if (!geoRes.ok) throw new Error('Location lookup failed');

      const geoData = await geoRes.json();
      if (!geoData.results || geoData.results.length === 0) {
        throw new Error('Location not found');
      }

      const location = geoData.results[0];
      const { latitude, longitude } = location;

      // Fetch weather data
      const tempUnit = settings.units === 'celsius' ? 'celsius' : 'fahrenheit';
      const weatherRes = await fetch(
        `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current_weather=true&temperature_unit=${tempUnit}&timezone=auto`
      );

      if (!weatherRes.ok) throw new Error('Weather fetch failed');

      const weatherJson = await weatherRes.json();
      setWeatherData({
        ...weatherJson.current_weather,
        location: `${location.name}${location.admin1 ? ', ' + location.admin1 : ''}`
      });
    } catch (err) {
      console.error('Weather fetch error:', err);
      setError('Unable to fetch weather data');
    } finally {
      setLoading(false);
    }
  };

  const getWeatherIcon = (weatherCode) => {
    const iconMap = {
      0: '☀️', 1: '🌤️', 2: '⛅️', 3: '☁️',
      45: '🌫️', 48: '🌫️',
      51: '🌦️', 53: '🌦️', 55: '🌦️',
      56: '🌧️', 57: '🌧️',
      61: '🌧️', 63: '🌧️', 65: '🌧️',
      66: '🌧️', 67: '🌧️',
      71: '❄️', 73: '❄️', 75: '❄️', 77: '❄️',
      80: '🌧️', 81: '🌧️', 82: '🌧️',
      85: '🌨️', 86: '🌨️',
      95: '⛈️', 96: '⛈️', 99: '⛈️'
    };
    return iconMap[weatherCode] || '❓';
  };

  const getWeatherDescription = (weatherCode) => {
    const descMap = {
      0: 'Clear sky', 1: 'Mainly clear', 2: 'Partly cloudy', 3: 'Overcast',
      45: 'Fog', 48: 'Depositing rime fog',
      51: 'Light drizzle', 53: 'Moderate drizzle', 55: 'Dense drizzle',
      56: 'Light freezing drizzle', 57: 'Dense freezing drizzle',
      61: 'Slight rain', 63: 'Moderate rain', 65: 'Heavy rain',
      66: 'Light freezing rain', 67: 'Heavy freezing rain',
      71: 'Slight snow', 73: 'Moderate snow', 75: 'Heavy snow', 77: 'Snow grains',
      80: 'Slight rain showers', 81: 'Moderate rain showers', 82: 'Violent rain showers',
      85: 'Slight snow showers', 86: 'Heavy snow showers',
      95: 'Thunderstorm', 96: 'Thunderstorm with hail', 99: 'Thunderstorm with heavy hail'
    };
    return descMap[weatherCode] || 'Unknown';
  };

  const tempUnit = settings.units === 'celsius' ? '°C' : '°F';

  let content = null;

  const placeholderTextSize = Math.max(14, 16 * scale);
  const placeholderIconSize = Math.max(24, 28 * scale);

  if (!settings.location) {
    content = (
      <div className="flex-1 flex flex-col items-center justify-center text-center text-white/70 space-y-2">
        <div style={{ fontSize: `${placeholderIconSize}px` }}>🌤️</div>
        <div style={{ fontSize: `${placeholderTextSize}px` }}>Set location in settings</div>
      </div>
    );
  } else if (loading) {
    content = (
      <div className="flex-1 flex items-center justify-center text-white/70" style={{ fontSize: `${placeholderTextSize}px` }}>
        Loading weather...
      </div>
    );
  } else if (error) {
    content = (
      <div className="flex-1 flex flex-col items-center justify-center text-center text-red-400 space-y-2">
        <div style={{ fontSize: `${placeholderIconSize}px` }}>❌</div>
        <div style={{ fontSize: `${placeholderTextSize}px` }}>{error}</div>
      </div>
    );
  } else if (!weatherData) {
    content = (
      <div className="flex-1 flex items-center justify-center text-white/70" style={{ fontSize: `${placeholderTextSize}px` }}>
        No weather data
      </div>
    );
  } else {
    const iconSize = Math.max(40, 48 * scale);
    const temperatureSize = Math.max(26, 34 * scale);
    const locationSize = Math.max(14, 16 * scale);
    const descriptionSize = Math.max(12, 14 * scale);

    content = (
      <div className="flex-1 flex flex-col items-center justify-center text-center space-y-3">
        <div style={{ fontSize: `${iconSize}px` }}>
          {getWeatherIcon(weatherData.weathercode)}
        </div>
        <div className="text-white font-bold" style={{ fontSize: `${temperatureSize}px` }}>
          {Math.round(weatherData.temperature)}{tempUnit}
        </div>
        <div className="text-white/70" style={{ fontSize: `${locationSize}px` }}>
          {weatherData.location}
        </div>
        {settings.showDetails && (
          <div className="text-white/50" style={{ fontSize: `${descriptionSize}px` }}>
            {getWeatherDescription(weatherData.weathercode)}
          </div>
        )}
        <div
          className="mt-4 h-px w-16 mx-auto bg-white/10"
          style={{ boxShadow: '0 0 14px var(--mirror-accent-soft)' }}
        />
      </div>
    );
  }

  return (
    <div ref={containerRef} className="w-full h-full flex flex-col p-4">
      {content}
    </div>
  );
};

export default WeatherApp;
